/**
 * 测试专用 Token 配置
 * 
 * Token 来源：后端文档 /smart_engine/docs/rbac/账号.md
 * 
 * ⚠️ 注意：Token 有有效期，如果失效请从以下途径获取新 Token：
 * 1. 从后端文档 /smart_engine/docs/rbac/账号.md 获取
 * 2. 从浏览器 localStorage 中复制：localStorage.getItem('Admin-Token')
 * 3. 联系后端团队获取新的永久 Token
 */

export const TEST_TOKENS = {
  /** 
   * 超管账号 Token（拥有所有权限）
   * ⚠️ 如果失效，请从 localStorage 复制或联系后端团队
   */
  ADMIN: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..TPsywlO7heqb9dsdvBG7r_5jKpTkGvPJiqwSYtsgVCA',
  
  /** 普通用户 Token */
  USER: 'eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9..3sVts7xt7-kbKZQ-1z37qqjuwGlAlBm8ugnUvs6CHfE',
} as const;

/**
 * 获取当前浏览器中存储的 Token
 * 在浏览器控制台中运行：getStoredToken()
 */
export function getStoredToken(): string | null {
  if (typeof localStorage !== 'undefined') {
    return localStorage.getItem('Admin-Token');
  }
  return null;
}

/**
 * 设置测试 Token 到 localStorage
 * @param tokenType - Token 类型：'ADMIN' | 'USER'
 */
export function setTestToken(tokenType: 'ADMIN' | 'USER' = 'ADMIN'): void {
  localStorage.setItem('Admin-Token', TEST_TOKENS[tokenType]);
  console.log(`已设置 ${tokenType} Token 到 localStorage`);
}

/**
 * 清除测试 Token
 */
export function clearTestToken(): void {
  localStorage.removeItem('Admin-Token');
  console.log('已清除 Admin-Token');
}
